document.addEventListener("DOMContentLoaded",()=>{const e=document.querySelector('[data-testid="widget-notes"]'),t=document.querySelector('[data-testid="widget-sessions"]');chrome.storage.local.get("notes",t=>{e.textContent=t.notes||"No Notes Saved"}),chrome.storage.local.get("sessions",e=>{const o=e.sessions||{};t.innerHTML="";for(const e in o){const o=document.createElement("div");o.textContent=e,t.appendChild(o)}})});